#include <stdio.h>
#include <stdint.h>

// Simulated memory array
uint8_t memory[65536];

// Bus control register simulation
volatile uint32_t *addr_reg = (uint32_t *)0x1000;
volatile uint32_t *data_reg = (uint32_t *)0x2000;
volatile uint32_t *control_reg = (uint32_t *)0x3000;

// Control bits
#define CTRL_READ  0x01
#define CTRL_WRITE 0x02
#define CTRL_READY 0x04

// Function to read from memory via bus
uint8_t memory_read(uint16_t address) {
    // Step 1: Place address on address bus
    *addr_reg = address;

    // Step 2: Set READ control signal
    *control_reg = CTRL_READ;

    // Step 3: Wait for memory response (with timeout)
    int wait_cycles = 0;
    while (!(*control_reg & CTRL_READY) && wait_cycles < 100) {
        wait_cycles++;
    }

    // Step 4: Read data from data bus
    uint8_t data = (uint8_t)*data_reg;

    // Step 5: Clear control signals
    *control_reg = 0;

    return data;
}

int main() {
    // Initialize some memory
    memory[0x0100] = 0xAA;
    memory[0x0101] = 0xBB;

    // Read data from memory
    uint8_t value = memory_read(0x0100);
    printf("Read value: 0x%02X\n", value);

    return 0;
}
